  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate, useLocation } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData, getViewportConstellations } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import useConstellationLinkMode from './hooks/useConstellationLinkMode';
 10→
 11→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 12→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 13→import NebulaLayer from './layers/NebulaLayer';
 14→import InteractiveLayer from './layers/InteractiveLayer';
 15→import WormholeLayer from './layers/WormholeLayer';
 16→import ConstellationLayer from './layers/ConstellationLayer';
 17→import UniverseMinimap from './components/UniverseMinimap';
 18→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 19→import {
 20→    buildSectorIndex,
 21→    computeGalaxyCentroids,
 22→    computeConstellationPullOffsets,
 23→    computeSectorKey,
 24→    getNeighborSectorKeys,
 25→} from './utils/cosmicPhysics';
 26→import { computeConstellationChains, assignChainColors } from './utils/constellationUtils';
 27→import { handleClickProfile } from '../../../helpers/handleClicks';
 28→import styles from './Universe.module.css';
 29→
 30→const SECTOR_SIZE = 2000;
 31→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 32→
 33→const Universe = () => {
 34→    const navigate = useNavigate();
 35→    const location = useLocation();
 36→    const { user, session } = useAuth();
 37→    const userId = user?.userData?.[0]?.id || null;
 38→
 39→    const fetchDebounceRef = useRef(null);
 40→    const settleDebounceRef = useRef(null);
 41→    const lastSettledPayloadRef = useRef('');
 42→    const initialFetchResolvedRef = useRef(false);
 43→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 44→    const ownGalaxyLookupStartedRef = useRef(false);
 45→    const constellationFlyToRef = useRef(location.state?.flyToConstellation || null);
 46→
 47→    const [posts, setPosts] = useState(new Map());
 48→    const [selectedPost, setSelectedPost] = useState(null);
 49→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 50→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 51→    const [pulsingId, setPulsingId] = useState(null);
 52→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 53→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 54→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 55→    const [wormholes, setWormholes] = useState([]);
 56→    const [isWarping, setIsWarping] = useState(false);
 57→    const [constellations, setConstellations] = useState([]);
 58→    const [linkModeError, setLinkModeError] = useState(null);
 59→
 60→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 61→    const [centroids, setCentroids] = useState([]);
 62→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 63→    const [similarPairs, setSimilarPairs] = useState([]);
 64→    const [starPulls, setStarPulls] = useState([]);
 65→
 66→    // Shared ref: prevents camera pan while dragging a star
 67→    const isStarDragging = useRef(false);
 68→
 69→    const {
 70→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 71→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 72→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
 73→
 74→    const {
 75→        isLinkMode, firstStar, secondStar, isSubmitting, linkModeStatus,
 76→        toggleLinkMode, cancelLinkMode, handleStarClickInLinkMode, submitLink,
 77→    } = useConstellationLinkMode(userId, session);
 78→
 79→    const [labelInput, setLabelInput] = useState('');
 80→
 81→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 82→    const showTitles = zoom > 0.5;
 83→
 84→    // Sector partitioning for scalable local gravity math.
 85→    const postSectorIndex = useMemo(() => (
 86→        buildSectorIndex(
 87→            postArray,
 88→            (post) => ({
 89→                x: post?.display_x ?? post?.universe_x,
 90→                y: post?.display_y ?? post?.universe_y,
 91→            }),
 92→            SECTOR_SIZE
 93→        )
 94→    ), [postArray]);
 95→
 96→    const centerSectorKey = useMemo(
 97→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 98→        [centerWorld.x, centerWorld.y]
 99→    );
100→
101→    const activeSectorKeys = useMemo(
102→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
103→        [centerSectorKey]
104→    );
105→
106→    const activePosts = useMemo(() => {
107→        if (activeSectorKeys.size === 0) return postArray;
108→
109→        const next = [];
110→        for (const key of activeSectorKeys) {
111→            const bucket = postSectorIndex.get(key);
112→            if (bucket?.length) next.push(...bucket);
113→        }
114→        return next;
115→    }, [postArray, postSectorIndex, activeSectorKeys]);
116→
117→    const activePostIds = useMemo(() => {
118→        const ids = new Set();
119→        for (const post of activePosts) {
120→            if (post?.id) ids.add(post.id);
121→        }
122→        return ids;
123→    }, [activePosts]);
124→
125→    const { centroidByUser } = useMemo(
126→        () => computeGalaxyCentroids(postArray),
127→        [postArray]
128→    );
129→
130→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
131→    const hashGalaxies = useMemo(() => {
132→        const seen = new Map();
133→        for (const post of postArray) {
134→            const uid = post.users?.id ?? post.user_id;
135→            if (!uid || seen.has(uid)) continue;
136→            const hash = userHomeCoords(uid);
137→            seen.set(uid, {
138→                userId: uid,
139→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
140→                x: hash.x,
141→                y: hash.y,
142→            });
143→        }
144→        return Array.from(seen.values());
145→    }, [postArray]);
146→
147→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
148→    const centroidTargets = useMemo(() => {
149→        const map = new Map();
150→        for (const c of centroids) {
151→            if (c.galaxy_x != null && c.galaxy_y != null) {
152→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
153→            }
154→        }
155→        return map;
156→    }, [centroids]);
157→
158→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
159→    const {
160→        galaxyPositions,
161→        starPullOffsets,
162→        isSettled,
163→        galaxyEdges: effectiveGalaxyEdges,
164→        hasEmbeddingGravity,
165→    } = useCosmicGravity({
166→        galaxies: hashGalaxies,
167→        centroidTargets,
168→        edges: galaxyEdges,
169→        posts: postArray,
170→        starPulls,
171→        centroidByUser,
172→        activeSectorKeys,
173→        activePostIds,
174→        sectorSize: SECTOR_SIZE,
175→    });
176→
177→    // ── Render galaxies = hash galaxies with animated positions ──────
178→    const galaxies = useMemo(() => {
179→        return hashGalaxies.map(g => {
180→            const animated = galaxyPositions.get(g.userId);
181→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
182→        });
183→    }, [hashGalaxies, galaxyPositions]);
184→
185→    // Home position for distance tracker — same resolution as auto-focus.
186→    const homePosition = useMemo(() => {
187→        if (!userId) return { x: 0, y: 0 };
188→        const ownGalaxy = galaxies.find((g) => g.userId === userId);
189→        if (ownGalaxy) return { x: ownGalaxy.x, y: ownGalaxy.y };
190→        return centroidTargets.get(userId) || ownGalaxyTarget || { x: 0, y: 0 };
191→    }, [userId, galaxies, centroidTargets, ownGalaxyTarget]);
192→
193→    const getComputedStarPosition = useCallback((post) => {
194→        if (!post) return null;
195→
196→        const uid = post.users?.id ?? post.user_id;
197→        const hashGal = userHomeCoords(uid);
198→        const animGal = galaxyPositions.get(uid);
199→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
200→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
201→        const pull = starPullOffsets.get(post.id);
202→
203→        const baseX = post.universe_x ?? post.display_x;
204→        const baseY = post.universe_y ?? post.display_y;
205→        if (baseX == null || baseY == null) return null;
206→
207→        return {
208→            x: baseX + galDx + (pull?.dx ?? 0),
209→            y: baseY + galDy + (pull?.dy ?? 0),
210→        };
211→    }, [galaxyPositions, starPullOffsets]);
212→
213→    // ── Hoisted computedStarPositions for sharing across layers ──────
214→    const computedStarPositions = useMemo(() => {
215→        const map = new Map();
216→        for (const post of postArray) {
217→            const uid = post.users?.id ?? post.user_id;
218→            const hashGal = userHomeCoords(uid);
219→            const animGal = galaxyPositions.get(uid);
220→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
221→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
222→            const pull = starPullOffsets.get(post.id);
223→
224→            const baseX = post.universe_x ?? post.display_x;
225→            const baseY = post.universe_y ?? post.display_y;
226→            if (baseX == null || baseY == null) continue;
227→
228→            let x = baseX + galDx + (pull?.dx ?? 0);
229→            let y = baseY + galDy + (pull?.dy ?? 0);
230→
231→            map.set(post.id, { x, y });
232→        }
233→        return map;
234→    }, [postArray, galaxyPositions, starPullOffsets]);
235→
236→    // ── Constellation pull offsets (spring constraint) ─────────────
237→    const acceptedConstellations = useMemo(
238→        () => constellations.filter(c => c.status === 'accepted'),
239→        [constellations]
240→    );
241→
242→    const constellationPullOffsets = useMemo(
243→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
244→        [acceptedConstellations, computedStarPositions]
245→    );
246→
247→    // ── Final star positions with constellation pull applied ───────
248→    const finalStarPositions = useMemo(() => {
249→        if (constellationPullOffsets.size === 0) return computedStarPositions;
250→
251→        const map = new Map(computedStarPositions);
252→        for (const [postId, offset] of constellationPullOffsets) {
253→            const pos = map.get(postId);
254→            if (pos) {
255→                map.set(postId, {
256→                    x: pos.x + offset.dx,
257→                    y: pos.y + offset.dy,
258→                });
259→            }
260→        }
261→        return map;
262→    }, [computedStarPositions, constellationPullOffsets]);
263→
264→    // ── Constellation chain colors ────────────────────────────────
265→    const chainColors = useMemo(() => {
266→        const chains = computeConstellationChains(acceptedConstellations);
267→        return assignChainColors(chains);
268→    }, [acceptedConstellations]);
269→
270→    // ── Map star ID → constellation chain color for ring indicators ─
271→    const constellationStarColors = useMemo(() => {
272→        const map = new Map();
273→        for (const c of acceptedConstellations) {
274→            const color = chainColors.get(c.id);
275→            if (!color) continue;
276→            if (!map.has(c.star_id_a)) map.set(c.star_id_a, color);
277→            if (!map.has(c.star_id_b)) map.set(c.star_id_b, color);
278→        }
279→        return map;
280→    }, [acceptedConstellations, chainColors]);
281→
282→    // Resolve logged-in user's galaxy target independently from viewport data.
283→    useEffect(() => {
284→        if (!userId) return;
285→        if (ownGalaxyLookupStartedRef.current) return;
286→
287→        ownGalaxyLookupStartedRef.current = true;
288→        let cancelled = false;
289→
290→        const resolveOwnGalaxyTarget = async () => {
291→            try {
292→                const { data, error } = await supabase
293→                    .from('galaxy_centroids')
294→                    .select('galaxy_x, galaxy_y')
295→                    .eq('user_id', userId)
296→                    .maybeSingle();
297→
298→                if (cancelled) return;
299→
300→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
301→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
302→                    setHasOwnPosts(true);
303→                    return;
304→                }
305→            } catch (err) {
306→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
307→            }
308→
309→            if (!cancelled) {
310→                setOwnGalaxyTarget(userHomeCoords(userId));
311→            }
312→        };
313→
314→        resolveOwnGalaxyTarget();
315→
316→        return () => {
317→            cancelled = true;
318→        };
319→    }, [userId]);
320→
321→    // One-time wormhole fetch on mount
322→    useEffect(() => {
323→        let cancelled = false;
324→
325→        const fetchWormholes = async () => {
326→            try {
327→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
328→                    similarity_threshold: 0.7,
329→                    min_distance: 0,
330→                    max_pairs: 30,
331→                });
332→                if (cancelled) return;
333→                if (error) {
334→                    console.warn('[universe] wormhole fetch error:', error.message);
335→                    return;
336→                }
337→                console.log('[universe] wormhole pairs:', data);
338→                if (Array.isArray(data) && data.length > 0) {
339→                    setWormholes(data);
340→                }
341→            } catch (err) {
342→                if (!cancelled) {
343→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
344→                }
345→            }
346→        };
347→
348→        fetchWormholes();
349→        return () => { cancelled = true; };
350→    }, []);
351→
352→    // Debounced fetch on camera/zoom change
353→    useEffect(() => {
354→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
355→
356→        fetchDebounceRef.current = setTimeout(async () => {
357→            const bounds = getViewportBounds();
358→            try {
359→                const result = await getUniversePosts(
360→                    bounds.minX,
361→                    bounds.maxX,
362→                    bounds.minY,
363→                    bounds.maxY,
364→                    200
365→                );
366→                if (result?.data) {
367→                    setPosts(prev => {
368→                        const next = new Map(prev);
369→                        for (const post of result.data) {
370→                            next.set(post.id, post);
371→                        }
372→                        return next;
373→                    });
374→                    if (userId && hasOwnPosts !== true) {
375→                        const ownsAny = result.data.some(p =>
376→                            (p.users?.id ?? p.user_id) === userId
377→                        );
378→                        if (ownsAny) setHasOwnPosts(true);
379→                    }
380→                }
381→                // Keep server gravity data as fallback when embeddings are absent in payload.
382→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
383→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
384→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
385→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
386→
387→                // Fetch constellations for visible posts
388→                if (result?.data?.length > 0) {
389→                    const visibleIds = result.data.map(p => p.id);
390→                    try {
391→                        const constResult = await getViewportConstellations(visibleIds);
392→                        if (constResult?.data) {
393→                            setConstellations(constResult.data);
394→                        }
395→                    } catch (constErr) {
396→                        console.warn('[universe] constellation fetch failed:', constErr?.message || constErr);
397→                    }
398→                }
399→            } catch (err) {
400→                console.error('Failed to fetch universe posts:', err);
401→            } finally {
402→                if (!initialFetchResolvedRef.current) {
403→                    initialFetchResolvedRef.current = true;
404→                    setIsInitialLoading(false);
405→                }
406→            }
407→        }, 400);
408→
409→        return () => {
410→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
411→        };
412→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
413→
414→    const handleStarClick = useCallback(async (post) => {
415→        if (isFlying.current) return;
416→
417→        // Intercept for link mode
418→        if (isLinkMode) {
419→            setLinkModeError(null);
420→            const result = await handleStarClickInLinkMode(post);
421→            if (result?.error) {
422→                setLinkModeError(result.error);
423→                setTimeout(() => setLinkModeError(null), 3000);
424→            }
425→            return;
426→        }
427→
428→        setSelectedPost(post);
429→        setSelectedGalaxy(null);
430→        setGalaxyProfile(null);
431→
432→        const position = getComputedStarPosition(post);
433→        if (!position) return;
434→
435→        flyTo(position.x, position.y, 1.2, () => {
436→            setPulsingId(post.id);
437→            setTimeout(() => setPulsingId(null), 700);
438→        });
439→    }, [flyTo, getComputedStarPosition, isFlying, isLinkMode, handleStarClickInLinkMode]);
440→
441→    const handleGalaxyClick = useCallback(async (galaxy) => {
442→        if (isFlying.current) return;
443→        setSelectedGalaxy(galaxy);
444→        setSelectedPost(null);
445→        setGalaxyProfile(null);
446→        flyTo(galaxy.x, galaxy.y, 0.8);
447→
448→        try {
449→            const data = await getUserData(galaxy.userId);
450→            const profile = data?.userData?.[0] || null;
451→            setGalaxyProfile(profile);
452→        } catch (err) {
453→            console.error('Failed to fetch galaxy profile:', err);
454→        }
455→    }, [flyTo, isFlying]);
456→
457→    const handleReadPost = useCallback(() => {
458→        if (!selectedPost) return;
459→        navigate(`/home/post/${selectedPost.id}`);
460→    }, [selectedPost, navigate]);
461→
462→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
463→        if (mode === 'drag') {
464→            jumpTo(worldX, worldY);
465→            return;
466→        }
467→        flyTo(worldX, worldY, zoom);
468→    }, [flyTo, jumpTo, zoom]);
469→
470→    // Enrich wormhole positions with live gravity-computed post coords
471→    const enrichedWormholes = useMemo(() => {
472→        return wormholes.map(wh => {
473→            const postA = posts.get(wh.post_a);
474→            const postB = posts.get(wh.post_b);
475→            const posA = postA ? getComputedStarPosition(postA) : null;
476→            const posB = postB ? getComputedStarPosition(postB) : null;
477→            return {
478→                ...wh,
479→                a_x: posA?.x ?? wh.a_x,
480→                a_y: posA?.y ?? wh.a_y,
481→                b_x: posB?.x ?? wh.b_x,
482→                b_y: posB?.y ?? wh.b_y,
483→            };
484→        });
485→    }, [wormholes, posts, getComputedStarPosition]);
486→
487→    // Find wormhole connection for a given post (if any)
488→    const getWormholeForPost = useCallback((postId) => {
489→        if (!postId || enrichedWormholes.length === 0) return null;
490→        for (const wh of enrichedWormholes) {
491→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
492→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
493→        }
494→        return null;
495→    }, [enrichedWormholes]);
496→
497→    const handleWormholeTravel = useCallback(() => {
498→        if (!selectedPost || isFlying.current) return;
499→        const match = getWormholeForPost(selectedPost.id);
500→        if (!match) return;
501→        const { wormhole, side } = match;
502→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
503→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
504→        setSelectedPost(null);
505→        setIsWarping(true);
506→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
507→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
508→
509→    // Find constellation links for a given post
510→    const getConstellationLinksForPost = useCallback((postId) => {
511→        if (!postId || acceptedConstellations.length === 0) return [];
512→        const links = [];
513→        for (const c of acceptedConstellations) {
514→            if (c.star_id_a === postId) {
515→                links.push({ constellation: c, targetStarId: c.star_id_b, targetTitle: c.b_title || 'Unnamed Star', label: c.label });
516→            } else if (c.star_id_b === postId) {
517→                links.push({ constellation: c, targetStarId: c.star_id_a, targetTitle: c.a_title || 'Unnamed Star', label: c.label });
518→            }
519→        }
520→        return links;
521→    }, [acceptedConstellations]);
522→
523→    const handleConstellationTravel = useCallback((targetStarId, constellation) => {
524→        if (isFlying.current) return;
525→        // Try live computed position first
526→        let targetPos = finalStarPositions.get(targetStarId);
527→        // Fallback to raw RPC positions from the constellation record
528→        if (!targetPos && constellation) {
529→            if (constellation.star_id_a === targetStarId && constellation.a_universe_x != null) {
530→                targetPos = { x: constellation.a_universe_x, y: constellation.a_universe_y };
531→            } else if (constellation.star_id_b === targetStarId && constellation.b_universe_x != null) {
532→                targetPos = { x: constellation.b_universe_x, y: constellation.b_universe_y };
533→            }
534→        }
535→        if (!targetPos) return;
536→        setSelectedPost(null);
537→        flyTo(targetPos.x, targetPos.y, zoom);
538→    }, [finalStarPositions, flyTo, isFlying, zoom]);
539→
540→    // One-time auto focus after first payload is loaded.
541→    // Skip if we have a constellation flyTo target — that effect handles it instead.
542→    useEffect(() => {
543→        if (!userId) return;
544→        if (isInitialLoading) return;
545→        if (hasAutoFocusedOwnGalaxyRef.current) return;
546→        if (constellationFlyToRef.current) return;
547→
548→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
549→        const target = ownGalaxy
550→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
551→            : (centroidTargets.get(userId) || ownGalaxyTarget);
552→
553→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
554→        if (!target) return;
555→
556→        hasAutoFocusedOwnGalaxyRef.current = true;
557→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
558→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
559→
560→    // Fly to constellation midpoint when arriving from a notification link.
561→    useEffect(() => {
562→        const target = constellationFlyToRef.current;
563→        if (!target) return;
564→        if (isInitialLoading) return;
565→
566→        const posA = finalStarPositions.get(target.starIdA);
567→        const posB = finalStarPositions.get(target.starIdB);
568→        if (!posA || !posB) return;
569→
570→        constellationFlyToRef.current = null;
571→        hasAutoFocusedOwnGalaxyRef.current = true;
572→
573→        const mx = (posA.x + posB.x) / 2;
574→        const my = (posA.y + posB.y) / 2;
575→        flyTo(mx, my, 1.0);
576→
577→        // Clear navigation state so refreshing doesn't re-trigger
578→        navigate(location.pathname, { replace: true, state: {} });
579→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
580→
581→    const settledPayload = useMemo(() => {
582→        if (!isSettled || activePosts.length === 0) return [];
583→
584→        const payload = [];
585→        for (const post of activePosts) {
586→            if (!post?.id) continue;
587→            const pos = getComputedStarPosition(post);
588→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
589→
590→            payload.push({
591→                post_id: post.id,
592→                settled_x: Math.round(pos.x * 100) / 100,
593→                settled_y: Math.round(pos.y * 100) / 100,
594→            });
595→        }
596→
597→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
598→        return payload;
599→    }, [activePosts, getComputedStarPosition, isSettled]);
600→
601→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
602→    useEffect(() => {
603→        if (!ENABLE_SETTLED_RPC_SAVE) return;
604→        if (!isSettled || settledPayload.length === 0) return;
605→
606→        const signature = JSON.stringify(settledPayload);
607→        if (signature === lastSettledPayloadRef.current) return;
608→
609→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
610→        settleDebounceRef.current = setTimeout(async () => {
611→            lastSettledPayloadRef.current = signature;
612→            try {
613→                const { error } = await supabase.rpc('save_universe_settled_positions', {
614→                    positions_payload: settledPayload,
615→                });
616→                if (error) {
617→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
618→                }
619→            } catch (err) {
620→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
621→            }
622→        }, 1200);
623→
624→        return () => {
625→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
626→        };
627→    }, [isSettled, settledPayload]);
628→
629→    // ESC key to cancel link mode
630→    useEffect(() => {
631→        if (!isLinkMode) return;
632→        const handleKeyDown = (e) => {
633→            if (e.key === 'Escape') cancelLinkMode();
634→        };
635→        window.addEventListener('keydown', handleKeyDown);
636→        return () => window.removeEventListener('keydown', handleKeyDown);
637→    }, [isLinkMode, cancelLinkMode]);
638→
639→    useEffect(() => {
640→        return () => {
641→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
642→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
643→        };
644→    }, []);
645→
646→    return (
647→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
648→            <button className={styles.backButton} onClick={() => navigate('/home')}>
649→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
650→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
651→                </svg>
652→                Back
653→            </button>
654→
655→            {userId && (
656→                <button
657→                    className={`${styles.linkModeButton} ${isLinkMode ? styles.linkModeActive : ''}`}
658→                    onClick={toggleLinkMode}
659→                    disabled={isSubmitting}
660→                >
661→                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
662→                        <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z"/>
663→                    </svg>
664→                    {isLinkMode
665→                        ? (secondStar ? 'Naming link...' : (firstStar ? 'Select second star...' : 'Select your star...'))
666→                        : 'Link Stars'}
667→                </button>
668→            )}
669→
670→            {isLinkMode && linkModeStatus === 'enter_label' && (
671→                <div className={styles.labelInputPanel}>
672→                    <div className={styles.labelInputHeader}>
673→                        Link "{firstStar?.title}" ↔ "{secondStar?.title}"
674→                    </div>
675→                    <input
676→                        className={styles.labelInputField}
677→                        type="text"
678→                        placeholder="Name this constellation (optional)"
679→                        value={labelInput}
680→                        onChange={(e) => setLabelInput(e.target.value)}
681→                        onKeyDown={(e) => {
682→                            if (e.key === 'Enter') {
683→                                submitLink(labelInput);
684→                                setLabelInput('');
685→                            }
686→                        }}
687→                        autoFocus
688→                    />
689→                    <div className={styles.labelInputActions}>
690→                        <button
691→                            className={styles.labelInputCreate}
692→                            disabled={isSubmitting}
693→                            onClick={() => {
694→                                submitLink(labelInput);
695→                                setLabelInput('');
696→                            }}
697→                        >
698→                            {isSubmitting ? 'Creating...' : 'Create Link'}
699→                        </button>
700→                        <button
701→                            className={styles.labelInputCancel}
702→                            onClick={() => {
703→                                cancelLinkMode();
704→                                setLabelInput('');
705→                            }}
706→                        >
707→                            Cancel
708→                        </button>
709→                    </div>
710→                </div>
711→            )}
712→
713→            {isLinkMode && linkModeStatus !== 'enter_label' && (
714→                <div className={styles.linkModeIndicator}>
715→                    <span>
716→                        {linkModeError
717→                            ? linkModeError
718→                            : firstStar
719→                                ? `Selected "${firstStar.title}" — now click another user's star`
720→                                : 'Click one of your stars to begin'}
721→                    </span>
722→                    <button className={styles.linkModeCancel} onClick={cancelLinkMode}>Cancel</button>
723→                </div>
724→            )}
725→
726→            <div className={styles.distanceTracker}>
727→                {(() => {
728→                    const dx = centerWorld.x - homePosition.x;
729→                    const dy = centerWorld.y - homePosition.y;
730→                    const dist = Math.round(Math.sqrt(dx * dx + dy * dy));
731→                    return dist < 50
732→                        ? 'Home'
733→                        : `${dist.toLocaleString()} Lightyears from Home`;
734→                })()}
735→            </div>
736→
737→            {isInitialLoading && (
738→                <div className={styles.loadingOverlay}>
739→                    <div className={styles.loadingCard}>
740→                        <div className={styles.loadingSpinner} />
741→                        <div className={styles.loadingText}>Loading universe...</div>
742→                    </div>
743→                </div>
744→            )}
745→
746→            <Stage
747→                ref={stageRef}
748→                width={stageSize.width}
749→                height={stageSize.height}
750→                {...stageEvents}
751→            >
752→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
753→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
754→                <NebulaLayer
755→                    layerProps={getLayerProps(0.85)}
756→                    galaxies={galaxies}
757→                    centroids={centroids}
758→                />
759→                {enrichedWormholes.length > 0 && (
760→                    <WormholeLayer
761→                        layerProps={getLayerProps(1.0)}
762→                        wormholes={enrichedWormholes}
763→                        zoom={zoom}
764→                    />
765→                )}
766→                {constellations.length > 0 && (
767→                    <ConstellationLayer
768→                        layerProps={getLayerProps(1.0)}
769→                        constellations={constellations}
770→                        computedStarPositions={finalStarPositions}
771→                        zoom={zoom}
772→                        chainColors={chainColors}
773→                        userId={userId}
774→                    />
775→                )}
776→                <InteractiveLayer
777→                    layerProps={getLayerProps(1.0)}
778→                    posts={postArray}
779→                    galaxies={galaxies}
780→                    zoom={zoom}
781→                    showTitles={showTitles}
782→                    pulsingId={pulsingId}
783→                    onStarClick={handleStarClick}
784→                    onGalaxyClick={handleGalaxyClick}
785→                    galaxyPositions={galaxyPositions}
786→                    starPullOffsets={starPullOffsets}
787→                    similarPairs={similarPairs}
788→                    galaxyEdges={effectiveGalaxyEdges}
789→                    activePostIds={activePostIds}
790→                    useEmbeddingBridges={hasEmbeddingGravity}
791→                    camera={camera}
792→                    stageSize={stageSize}
793→                    computedStarPositions={finalStarPositions}
794→                    constellationStarColors={constellationStarColors}
795→                />
796→            </Stage>
797→
798→            {isWarping && <div className={styles.warpOverlay} />}
799→
800→            <UniverseMinimap
801→                galaxies={galaxies}
802→                camera={camera}
803→                zoom={zoom}
804→                stageSize={stageSize}
805→                onNavigate={handleMinimapNavigate}
806→                constellations={acceptedConstellations}
807→                computedStarPositions={finalStarPositions}
808→            />
809→
810→            {selectedGalaxy && galaxyProfile && (
811→                <div className={styles.galaxyPreviewPanel}>
812→                    <button
813→                        className={styles.galaxyPreviewClose}
814→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
815→                    >
816→                        &times;
817→                    </button>
818→                    <div
819→                        className={styles.galaxyPreviewBg}
820→                        style={galaxyProfile.background || {}}
821→                    />
822→                    <div className={styles.galaxyPreviewContent}>
823→                        <img
824→                            className={styles.galaxyPreviewAvatar}
825→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
826→                            alt=""
827→                        />
828→                        <div className={styles.galaxyPreviewHeading}>
829→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
830→                        </div>
831→                        {galaxyProfile.bio && (
832→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
833→                        )}
834→                        <button
835→                            className={styles.galaxyPreviewVisitBtn}
836→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
837→                        >
838→                            Visit Profile
839→                        </button>
840→                    </div>
841→                </div>
842→            )}
843→
844→            {selectedPost && (
845→                <div className={styles.previewPanel}>
846→                    <button
847→                        className={styles.previewClose}
848→                        onClick={() => setSelectedPost(null)}
849→                    >
850→                        &times;
851→                    </button>
852→                    <div className={styles.previewAuthor}>
853→                        <img
854→                            className={styles.previewAvatar}
855→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
856→                            alt=""
857→                        />
858→                        <span className={styles.previewAuthorName}>
859→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
860→                        </span>
861→                    </div>
862→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
863→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
864→                    <div className={styles.previewLikes}>
865→                        {(() => {
866→                            const count = selectedPost.like_count != null
867→                                ? selectedPost.like_count
868→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
869→                                    ? selectedPost.likes[0].count : 0);
870→                            return `${count} like${count !== 1 ? 's' : ''}`;
871→                        })()}
872→                    </div>
873→                    <div className={styles.previewActions}>
874→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
875→                            Read
876→                        </button>
877→                        {getWormholeForPost(selectedPost.id) && (
878→                            <div className={styles.wormholeBtnWrap}>
879→                                <button className={styles.wormholeBtn} onClick={handleWormholeTravel}>
880→                                    Wormhole to "{getWormholeForPost(selectedPost.id).targetTitle}"
881→                                </button>
882→                                <div className={styles.wormholeTooltip}>
883→                                    This post is semantically linked to a distant post. Click to warp there instantly.
884→                                </div>
885→                            </div>
886→                        )}
887→                        {getConstellationLinksForPost(selectedPost.id).map((link) => (
888→                            <button
889→                                key={link.constellation.id}
890→                                className={styles.constellationBtn}
891→                                onClick={() => handleConstellationTravel(link.targetStarId, link.constellation)}
892→                            >
893→                                {link.label ? `${link.label} \u2192 "${link.targetTitle}"` : `Fly to "${link.targetTitle}"`}
894→                            </button>
895→                        ))}
896→                    </div>
897→                </div>
898→            )}
899→        </div>
900→    );
901→};
902→
903→export default Universe;
