                    ctx.lineWidth = 8;
                    ctx.lineCap = 'round';
                    ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
                    ctx.shadowBlur = underglowBlur;
                    ctx.setLineDash([]);
                    ctx.beginPath();
                    ctx.moveTo(ax, ay);
                    ctx.lineTo(bx, by);
                    ctx.stroke();
                    ctx.restore();

