import React, { useRef, useEffect, useCallback, useMemo } from 'react';
import { Layer, Shape, Text, Line } from 'react-konva';
import { STAR_COLORS } from '../utils/starUtils';

const parseHex = (hex) => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
});

const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId, onConstellationFocus, focusedConstellationId }) => {
    const shapeRef = useRef(null);
    const animRef = useRef({ time: 0, raf: null });

    const linkData = useMemo(() => {
        if (!Array.isArray(constellations) || constellations.length === 0) return [];
        return constellations.map((link, i) => {
            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
            const rgb = parseHex(colorHex);
            const isPending = link.status === 'pending';
            const isDeclined = link.status === 'declined';
            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
            return { ...link, rgb, colorHex, isPending, isDeclined, isOwnPending };
        });
    }, [constellations, chainColors, userId]);

    // Resolve positions for each link
    const resolvedLinks = useMemo(() => {
        return linkData
            .filter(link => !link.isDeclined)
            .filter(link => !link.isPending || link.isOwnPending)
            .map(link => {
                const posA = computedStarPositions.get(link.star_id_a)
                    || (link.a_universe_x != null ? { x: link.a_universe_x, y: link.a_universe_y } : null);
                const posB = computedStarPositions.get(link.star_id_b)
                    || (link.b_universe_x != null ? { x: link.b_universe_x, y: link.b_universe_y } : null);
                if (!posA || !posB) return null;
                return { ...link, ax: posA.x, ay: posA.y, bx: posB.x, by: posB.y };
            })
            .filter(Boolean);
    }, [linkData, computedStarPositions]);

    const animate = useCallback(() => {
        animRef.current.time = performance.now();
        const node = shapeRef.current;
        if (node) {
            const layer = node.getLayer();
            if (layer) layer.batchDraw();
        }
        animRef.current.raf = requestAnimationFrame(animate);
    }, []);

    useEffect(() => {
        const hasAccepted = resolvedLinks.some(l => !l.isPending);
        if (!hasAccepted) return;
        animRef.current.raf = requestAnimationFrame(animate);
        return () => {
            if (animRef.current.raf) cancelAnimationFrame(animRef.current.raf);
        };
    }, [animate, resolvedLinks]);

    if (resolvedLinks.length === 0) return null;

    // Separate labels for Konva Text nodes (need scaleX/scaleY zoom correction)
    const labels = resolvedLinks.filter(l => !l.isPending && l.label);

    return (
        <Layer {...layerProps}>
            <Shape
                ref={shapeRef}
                sceneFunc={(ctx) => {
                    const time = animRef.current.time || performance.now();
                    const hasFocus = focusedConstellationId != null;

                    for (const link of resolvedLinks) {
                        const { ax, ay, bx, by, rgb } = link;
                        const isFocusedLine = hasFocus && link.id === focusedConstellationId;
                        const isDimmedLine = hasFocus && !isFocusedLine;

                        if (link.isPending) {
                            // Pending: simple faint dashed line
                            ctx.save();
                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${isDimmedLine ? 0.01 : 0.08})`;
                            ctx.lineWidth = 1;
                            ctx.setLineDash([5, 10]);
                            ctx.lineCap = 'round';
                            ctx.beginPath();
                            ctx.moveTo(ax, ay);
                            ctx.lineTo(bx, by);
                            ctx.stroke();
                            ctx.restore();
                            continue;
                        }

                        // Accepted: triple-layer glow (boosted when focused, dimmed otherwise)
                        const underglowOpacity = isFocusedLine ? 0.15 : isDimmedLine ? 0.02 : 0.06;
                        const bodyOpacity = isFocusedLine ? 0.3 : isDimmedLine ? 0.02 : 0.12;
                        const coreOpacity = isFocusedLine ? 0.7 : isDimmedLine ? 0.02 : 0.45;
                        const underglowBlur = isFocusedLine ? 30 : 20;
                        const bodyBlur = isFocusedLine ? 14 : 8;

                        // Layer 1: Wide underglow
                        ctx.save();
                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${underglowOpacity})`;
                        ctx.lineWidth = 8;
                        ctx.lineCap = 'round';
                        ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
                        ctx.shadowBlur = underglowBlur;
                        ctx.setLineDash([]);
                        ctx.beginPath();
                        ctx.moveTo(ax, ay);
                        ctx.lineTo(bx, by);
                        ctx.stroke();
                        ctx.restore();

                        // Layer 2: Medium body
                        ctx.save();
                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${bodyOpacity})`;
                        ctx.lineWidth = 3;
                        ctx.lineCap = 'round';
                        ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
                        ctx.shadowBlur = bodyBlur;
                        ctx.setLineDash([]);
                        ctx.beginPath();
                        ctx.moveTo(ax, ay);
                        ctx.lineTo(bx, by);
                        ctx.stroke();
                        ctx.restore();

                        // Layer 3: Thin animated core
                        ctx.save();
                        ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${coreOpacity})`;
                        ctx.lineWidth = 1.2;
                        ctx.lineCap = 'round';
                        ctx.setLineDash([14, 10]);
                        ctx.lineDashOffset = time * 0.04;
                        ctx.beginPath();
                        ctx.moveTo(ax, ay);
                        ctx.lineTo(bx, by);
                        ctx.stroke();
                        ctx.restore();
                    }
                }}
                perfectDrawEnabled={false}
                listening={false}
            />
            {/* Labels rendered as Konva Text for zoom correction */}
            {labels.map((link) => {
                const mx = (link.ax + link.bx) / 2;
                const my = (link.ay + link.by) / 2;
                return (
                    <Text
                        key={`label-${link.id}`}
                        x={mx}
                        y={my - 14}
                        text={link.label}
                        fontSize={12}
                        fontFamily="sans-serif"
                        fill={`rgba(${link.rgb.r},${link.rgb.g},${link.rgb.b},0.7)`}
                        align="center"
                        offsetX={link.label.length * 3}
                        scaleX={1 / zoom}
                        scaleY={1 / zoom}
                        listening={false}
                        perfectDrawEnabled={false}
                    />
                );
            })}
            {/* Invisible hit detection lines for accepted constellations */}
            {resolvedLinks.filter(l => !l.isPending).map((link) => (
                <Line
                    key={`hit-${link.id}`}
                    points={[link.ax, link.ay, link.bx, link.by]}
                    stroke="transparent"
                    strokeWidth={1}
                    hitStrokeWidth={20}
                    onClick={() => onConstellationFocus?.(link)}
                    onTap={() => onConstellationFocus?.(link)}
                    perfectDrawEnabled={false}
                />
            ))}
        </Layer>
    );
});

ConstellationLayer.displayName = 'ConstellationLayer';

export default ConstellationLayer;

